const now = new Date();
const fmt = d => d.toISOString().slice(0,10);
return [{ today: fmt(now), yday: fmt(new Date(now.getTime()-24*3600*1000)) }];

const collect = items => items.flatMap(it => (it.json.dates||[]).flatMap(d => d.games||[]));
const t = $items('03 Schedule Today', 0);
const y = $items('03b Schedule Yesterday', 0);
const games = [...collect(t), ...collect(y)];
const n = Date.now();
const pre = 10*60*1000;
const post = 6*3600*1000;
const active = games.filter(g => { try { const s = new Date(g.gameDate).getTime(); return (s-pre) <= n && n <= (s+post); } catch(e) { return false; } });
return active.map(g => ({ json: { gamePk: g.gamePk } }));

const HomerCache = require('/Users/benbirkhahn/HomerTrakker/scripts/homer_cache.js');
const cache = new HomerCache('/Users/benbirkhahn/HomerTrakker');

const plays = $json.liveData?.plays?.allPlays || [];
const gamePk = $item(0).$node['04 Filter Active Games'].json.gamePk;
const today = $item(0).$node['02 Compute Dates'].json.today;
const out = [];

for (const p of plays) {
  if (p.result?.eventType !== 'home_run') continue;

  const atBatIndex = p.about?.atBatIndex;
  if (cache.hasHomeRun(today, gamePk, atBatIndex)) continue;

  cache.markHomeRun(today, gamePk, atBatIndex);
  out.push({ json: { gamePk, play: p } });
}

return out;

const content = $json;
const play = $item(0).$node['06 Extract New HR Plays'].json.play;
const gamePk = $item(0).$node['06 Extract New HR Plays'].json.gamePk;
const batterId = play?.matchup?.batter?.id;
const items = content.highlights?.highlights?.items || [];
const isHRItem = it => ((it.headline||it.title||'').toLowerCase().includes('home run'));
const byBatter = it => { if (!batterId) return true; return (it.keywordsAll||[]).some(k => k.type==='player' && String(k.playerId)===String(batterId)); };
const links = [];
for (const it of items) {
  if (!(isHRItem(it) && byBatter(it))) continue;
  for (const pb of (it.playbacks||[])) { const url = pb.url||''; if (url.endsWith('.mp4')) links.push(url); }
}
const diamond = links.filter(u=>u.includes('mlb-cuts-diamond.mlb.com'));
const darkroom = links.filter(u=>u.includes('darkroom-clips.mlb.com'));
const prefer4000K = arr => arr.find(u=>u.includes('4000K')) || arr[0] || null;
const d = prefer4000K(diamond);
const a = darkroom[0] || null;
if (!(d && a)) return [];
return [{ json: { gamePk, play, d, a } }];

const HomerCache = require('/Users/benbirkhahn/HomerTrakker/scripts/homer_cache.js');
const cache = new HomerCache('/Users/benbirkhahn/HomerTrakker');

const play = $json.play;
const gamePk = $json.gamePk;
const d = $json.d;
const a = $json.a;
const batter = (play.matchup && play.matchup.batter && play.matchup.batter.fullName) || 'Unknown Player';
const pitcher = (play.matchup && play.matchup.pitcher && play.matchup.pitcher.fullName) || '';
const inning = ((play.about && play.about.halfInning) ? play.about.halfInning : '') + ' ' + ((play.about && play.about.inning) ? play.about.inning : '');
const desc = (play.result && play.result.description) || '';
const today = $item(0).$node['02 Compute Dates'].json.today;
function pad(n){ return n<10 ? ('0'+n) : (''+n); }
const now = new Date();
const ts = now.getFullYear().toString() + pad(now.getMonth()+1) + pad(now.getDate()) + '_' + pad(now.getHours()) + pad(now.getMinutes()) + pad(now.getSeconds());

// Get sequence number from cache
const num = cache.getNextSeq(today);

const lines = [];
lines.push('TONIGHT\'S HOME RUN - READY FOR @homertrakker');
lines.push('=======================================================');
lines.push('');
lines.push('CAPTION:');
lines.push('🏠⚾ HOME RUN ALERT! ⚾🏠');
lines.push('🔥 ' + batter);
if (pitcher) lines.push('⚾ vs ' + pitcher);
if (inning.trim()) lines.push('📊 ' + inning.trim());
if (desc) lines.push(desc);
lines.push('');
lines.push('HASHTAGS:');
lines.push('#MLB #HomeRun #Baseball #MLBShorts #Statcast');
lines.push('');
lines.push('VIDEOS:');
lines.push('1. clip');
lines.push('   ' + d);
lines.push('2. clip');
lines.push('   ' + a);
lines.push('');
lines.push('HOME RUN DATA:');
lines.push('GamePk: ' + gamePk);
lines.push('Batter: ' + batter);
if (inning.trim()) lines.push('Inning: ' + inning.trim());
const postText = lines.join('\n') + '\n';
const baseDir = '/Users/benbirkhahn/HomerTrakker';
const postsDir = baseDir + '/MLB_HomeRun_Posts/' + today;
const videosDir = postsDir + '/videos';
const postPath = postsDir + '/tonights_homer_' + num + '_' + ts + '.txt';
function basename(u){ try{ return new URL(u).pathname.split('/').pop() }catch(e){ return 'clip.mp4'; } }
const file1 = 'homer_' + num + '_1_' + basename(d);
const file2 = 'homer_' + num + '_2_animated_' + basename(a);
const video1Path = videosDir + '/' + file1;
const video2Path = videosDir + '/' + file2;
return [{ json: { today, num, postText, postPath, postsDir, videosDir, d, a, video1Path, video2Path, gamePk } }];
